import 'dart:convert';
import 'dart:io';
import 'dart:typed_data';
import 'package:crypto/crypto.dart' as crypto_lib;
import 'package:http/http.dart' as http;
import 'package:mime/mime.dart';
import 'package:path/path.dart' as p;
import 'package:uuid/uuid.dart';
import '../config/credentials.dart';

// Note: For a real hackathon you'd use a package like aws_s3_upload.
// This manual implementation avoids extra dependencies and shows the signing process.

class S3UploadService {
  static Future<String> uploadFile(File file) async {
    final accessKey = AppCredentials.awsAccessKeyId;
    final secretKey = AppCredentials.awsSecretAccessKey;
    final bucket = AppCredentials.awsS3Bucket;
    final region = AppCredentials.awsRegion;

    final uuid = const Uuid().v4();
    final extension = p.extension(file.path);
    final key = 'uploads/$uuid$extension';
    final contentType =
        lookupMimeType(file.path) ?? 'application/octet-stream';

    final bytes = await file.readAsBytes();
    final now = DateTime.now().toUtc();
    final dateStamp = _formatDate(now);
    final amzDate = _formatAmzDate(now);
    final host = '$bucket.s3.$region.amazonaws.com';
    final url = Uri.parse('https://$host/$key');

    final payloadHash = _sha256Hex(bytes);

    final headers = <String, String>{
      'Host': host,
      'Content-Type': contentType,
      'x-amz-content-sha256': payloadHash,
      'x-amz-date': amzDate,
    };

    final signedHeaders = (headers.keys.map((k) => k.toLowerCase()).toList()
          ..sort())
        .join(';');

    final canonicalHeaders = (headers.keys.toList()
          ..sort((a, b) => a.toLowerCase().compareTo(b.toLowerCase())))
        .map((k) => '${k.toLowerCase()}:${headers[k]!.trim()}')
        .join('\n');

    final canonicalRequest = [
      'PUT',
      '/$key',
      '',
      '$canonicalHeaders\n',
      signedHeaders,
      payloadHash,
    ].join('\n');

    final credentialScope = '$dateStamp/$region/s3/aws4_request';
    final stringToSign = [
      'AWS4-HMAC-SHA256',
      amzDate,
      credentialScope,
      _sha256Hex(utf8.encode(canonicalRequest)),
    ].join('\n');

    final signingKey = _getSignatureKey(secretKey, dateStamp, region, 's3');
    final signature = _hmacSha256Hex(signingKey, utf8.encode(stringToSign));

    final authorization =
        'AWS4-HMAC-SHA256 Credential=$accessKey/$credentialScope, '
        'SignedHeaders=$signedHeaders, Signature=$signature';

    headers['Authorization'] = authorization;

    final response = await http.put(url, headers: headers, body: bytes);

    if (response.statusCode == 200 || response.statusCode == 201) {
      return url.toString();
    } else {
      throw Exception(
        'S3 upload failed: ${response.statusCode} ${response.body}',
      );
    }
  }

  static String _formatDate(DateTime dt) =>
      '${dt.year}${dt.month.toString().padLeft(2, '0')}${dt.day.toString().padLeft(2, '0')}';

  static String _formatAmzDate(DateTime dt) =>
      '${_formatDate(dt)}T${dt.hour.toString().padLeft(2, '0')}'
      '${dt.minute.toString().padLeft(2, '0')}'
      '${dt.second.toString().padLeft(2, '0')}Z';

  static String _sha256Hex(List<int> data) =>
      crypto_lib.sha256.convert(data).toString();

  static Uint8List _hmacSha256(List<int> key, List<int> data) {
    final hmac = crypto_lib.Hmac(crypto_lib.sha256, key);
    return Uint8List.fromList(hmac.convert(data).bytes);
  }

  static String _hmacSha256Hex(List<int> key, List<int> data) {
    final hmac = crypto_lib.Hmac(crypto_lib.sha256, key);
    return hmac.convert(data).toString();
  }

  static Uint8List _getSignatureKey(
    String secretKey,
    String dateStamp,
    String region,
    String service,
  ) {
    final kDate = _hmacSha256(
      utf8.encode('AWS4$secretKey'),
      utf8.encode(dateStamp),
    );
    final kRegion = _hmacSha256(kDate, utf8.encode(region));
    final kService = _hmacSha256(kRegion, utf8.encode(service));
    final kSigning = _hmacSha256(kService, utf8.encode('aws4_request'));
    return kSigning;
  }
}

// ---- File: lib/services/vision_service.dart ----

import 'dart:convert';
import 'dart:io';
import 'package:http/http.dart' as http;
import '../config/credentials.dart';

class VisionAnalysisResult {
  final List<String> labels;
  final List<String> texts;
  final String? dominantColor;
  final bool isExplicit;
  final Map<String, dynamic> rawResponse;

  VisionAnalysisResult({
    required this.labels,
    required this.texts,
    this.dominantColor,
    required this.isExplicit,
    required this.rawResponse,
  });
}

class VisionService {
  static const _baseUrl =
      'https://vision.googleapis.com/v1/images:annotate';

  static Future<VisionAnalysisResult> analyzeImage(File imageFile) async {
    final apiKey = AppCredentials.googleCloudApiKey;
    final bytes = await imageFile.readAsBytes();
    final base64Image = base64Encode(bytes);

    final requestBody = {
      'requests': [
        {
          'image': {'content': base64Image},
          'features': [
            {'type': 'LABEL_DETECTION', 'maxResults': 10},
            {'type': 'TEXT_DETECTION', 'maxResults': 5},
            {'type': 'IMAGE_PROPERTIES', 'maxResults': 1},
            {'type': 'SAFE_SEARCH_DETECTION'},
          ],
        },
      ],
    };

    final response = await http.post(
      Uri.parse('$_baseUrl?key=$apiKey'),
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode(requestBody),
    );

    if (response.statusCode != 200) {
      throw Exception(
        'Vision API error: ${response.statusCode} ${response.body}',
      );
    }

    final json = jsonDecode(response.body) as Map<String, dynamic>;
    final responses = json['responses'] as List;

    if (responses.isEmpty) {
      throw Exception('Empty response from Vision API');
    }

    final result = responses[0] as Map<String, dynamic>;

    // Parse labels
    final labels = <String>[];
    if (result.containsKey('labelAnnotations')) {
      for (final label in result['labelAnnotations'] as List) {
        final description = label['description'] as String?;
        final score = (label['score'] as num?)?.toDouble() ?? 0;
        if (description != null) {
          labels.add('$description (${(score * 100).toStringAsFixed(1)}%)');
        }
      }
    }

    // Parse text
    final texts = <String>[];
    if (result.containsKey('textAnnotations')) {
      for (final text in result['textAnnotations'] as List) {
        final description = text['description'] as String?;
        if (description != null) {
          texts.add(description);
        }
      }
    }

    // Parse dominant color
    String? dominantColor;
    if (result.containsKey('imagePropertiesAnnotation')) {
      final props = result['imagePropertiesAnnotation'] as Map<String, dynamic>;
      final colors = props['dominantColors']?['colors'] as List?;
      if (colors != null && colors.isNotEmpty) {
        final color = colors[0]['color'] as Map<String, dynamic>?;
        if (color != null) {
          final r = (color['red'] as num?)?.toInt() ?? 0;
          final g = (color['green'] as num?)?.toInt() ?? 0;
          final b = (color['blue'] as num?)?.toInt() ?? 0;
          dominantColor = 'RGB($r, $g, $b)';
        }
      }
    }

    // Parse safe search
    bool isExplicit = false;
    if (result.containsKey('safeSearchAnnotation')) {
      final safe = result['safeSearchAnnotation'] as Map<String, dynamic>;
      const riskyLevels = ['LIKELY', 'VERY_LIKELY'];
      isExplicit = riskyLevels.contains(safe['adult']) ||
          riskyLevels.contains(safe['violence']);
    }

    return VisionAnalysisResult(
      labels: labels,
      texts: texts,
      dominantColor: dominantColor,
      isExplicit: isExplicit,
      rawResponse: result,
    );
  }
}

