class HomeScreen extends StatefulWidget {
  const HomeScreen({super.key});

  @override
  State<HomeScreen> createState() => _HomeScreenState();
}

enum AppState { idle, picking, uploading, analyzing, done, error }

class _HomeScreenState extends State<HomeScreen> {
  final ImagePicker _picker = ImagePicker();

  AppState _state = AppState.idle;
  File? _selectedImage;
  String? _uploadedUrl;
  VisionAnalysisResult? _analysisResult;
  String? _errorMessage;

  Future<void> _pickAndProcess(ImageSource source) async {
    try {
      setState(() {
        _state = AppState.picking;
        _errorMessage = null;
        _analysisResult = null;
        _uploadedUrl = null;
      });

      final XFile? picked = await _picker.pickImage(
        source: source,
        maxWidth: 1920,
        maxHeight: 1920,
        imageQuality: 85,
      );

      if (picked == null) {
        setState(() => _state = AppState.idle);
        return;
      }

      final file = File(picked.path);
      setState(() {
        _selectedImage = file;
        _state = AppState.uploading;
      });

      // Upload to S3
      final url = await S3UploadService.uploadFile(file);
      setState(() {
        _uploadedUrl = url;
        _state = AppState.analyzing;
      });

      // Analyze with Vision API
      final result = await VisionService.analyzeImage(file);
      setState(() {
        _analysisResult = result;
        _state = AppState.done;
      });
    } catch (e) {
      setState(() {
        _state = AppState.error;
        _errorMessage = e.toString();
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('📸 Photo Analyzer'),
        centerTitle: true,
        elevation: 2,
      ),
      body: SingleChildScrollView(
        padding: const EdgeInsets.all(16),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            // Image preview
            if (_selectedImage != null)
              ClipRRect(
                borderRadius: BorderRadius.circular(12),
                child: Image.file(
                  _selectedImage!,
                  height: 300,
                  fit: BoxFit.cover,
                ),
              )
            else
              Container(
                height: 250,
                decoration: BoxDecoration(
                  color: Colors.grey.shade200,
                  borderRadius: BorderRadius.circular(12),
                  border: Border.all(color: Colors.grey.shade300),
                ),
                child: const Center(
                  child: Column(
                    mainAxisAlignment: MainAxisAlignment.center,
                    children: [
                      Icon(Icons.photo_library, size: 64, color: Colors.grey),
                      SizedBox(height: 8),
                      Text(
                        'Select a photo to analyze',
                        style: TextStyle(color: Colors.grey, fontSize: 16),
                      ),
                    ],
                  ),
                ),
              ),

            const SizedBox(height: 16),

            // Action buttons
            Row(
              children: [
                Expanded(
                  child: ElevatedButton.icon(
                    onPressed: _state == AppState.uploading ||
                            _state == AppState.analyzing
                        ? null
                        : () => _pickAndProcess(ImageSource.gallery),
                    icon: const Icon(Icons.photo_library),
                    label: const Text('Gallery'),
                    style: ElevatedButton.styleFrom(
                      padding: const EdgeInsets.symmetric(vertical: 14),
                    ),
                  ),
                ),
                const SizedBox(width: 12),
                Expanded(
                  child: ElevatedButton.icon(
                    onPressed: _state == AppState.uploading ||
                            _state == AppState.analyzing
                        ? null
                        : () => _pickAndProcess(ImageSource.camera),
                    icon: const Icon(Icons.camera_alt),
                    label: const Text('Camera'),
                    style: ElevatedButton.styleFrom(
                      padding: const EdgeInsets.symmetric(vertical: 14),
                    ),
                  ),
                ),
              ],
            ),

            const SizedBox(height: 20),

            // Status indicator
            if (_state == AppState.uploading)
              const _StatusCard(
                icon: Icons.cloud_upload,
                color: Colors.blue,
                title: 'Uploading to S3...',
                showProgress: true,
              ),

            if (_state == AppState.analyzing)
              const _StatusCard(
                icon: Icons.psychology,
                color: Colors.purple,
                title: 'Analyzing with Google Vision...',
                showProgress: true,
              ),

            if (_state == AppState.error && _errorMessage != null)
              _StatusCard(
                icon: Icons.error,
                color: Colors.red,
                title: 'Error',
                subtitle: _errorMessage,
                showProgress: false,
              ),

            // Upload URL
            if (_uploadedUrl != null) ...[
              Card(
                color: Colors.green.shade50,
                child: Padding(
                  padding: const EdgeInsets.all(12),
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Row(
                        children: [
                          Icon(Icons.check_circle, color: Colors.green.shade700),
                          const SizedBox(width: 8),
                          Text(
                            'Uploaded to S3',
                            style: TextStyle(
                              fontWeight: FontWeight.bold,
                              color: Colors.green.shade700,
                            ),
                          ),
                        ],
                      ),
                      const SizedBox(height: 8),
                      Text(
                        _uploadedUrl!,
                        style: const TextStyle(fontSize: 11),
                        maxLines: 2,
                        overflow: TextOverflow.ellipsis,
                      ),
                    ],
                  ),
                ),
              ),
              const SizedBox(height: 12),
            ],

            // Analysis results
            if (_analysisResult != null) ...[
              // Safety warning
              if (_analysisResult!.isExplicit)
                Card(
                  color: Colors.red.shade50,
                  child: const Padding(
                    padding: EdgeInsets.all(12),
                    child: Row(
                      children: [
                        Icon(Icons.warning, color: Colors.red),
                        SizedBox(width: 8),
                        Text(
                          'Content flagged by SafeSearch',
                          style: TextStyle(
                            color: Colors.red,
                            fontWeight: FontWeight.bold,
                          ),
                        ),
                      ],
                    ),
                  ),
                ),

              // Labels
              if (_analysisResult!.labels.isNotEmpty)
                _ResultSection(
                  title: '🏷️ Labels',
                  icon: Icons.label,
                  child: Wrap(
                    spacing: 8,
                    runSpacing: 8,
                    children: _analysisResult!.labels
                        .map(
                          (label) => Chip(
                            label: Text(label, style: const TextStyle(fontSize: 12)),
                            backgroundColor: Colors.indigo.shade50,
                          ),
                        )
                        .toList(),
                  ),
                ),

              // Detected text
              if (_analysisResult!.texts.isNotEmpty)
                _ResultSection(
                  title: '📝 Detected Text',
                  icon: Icons.text_fields,
                  child: Text(
                    _analysisResult!.texts.first,
                    style: const TextStyle(fontSize: 14),
                  ),
                ),

              // Dominant color
              if (_analysisResult!.dominantColor != null)
                _ResultSection(
                  title: '🎨 Dominant Color',
                  icon: Icons.palette,
                  child: Row(
                    children: [
                      Container(
                        width: 32,
                        height: 32,
                        decoration: BoxDecoration(
                          color: _parseColor(_analysisResult!.dominantColor!),
                          borderRadius: BorderRadius.circular(6),
                          border: Border.all(color: Colors.grey.shade300),
                        ),
                      ),
                      const SizedBox(width: 12),
                      Text(
                        _analysisResult!.dominantColor!,
                        style: const TextStyle(fontSize: 14),
                      ),
                    ],
                  ),
                ),
            ],
          ],
        ),
      ),
    );
  }

  Color _parseColor(String colorStr) {
    final match = RegExp(r'RGB\((\d+),\s*(\d+),\s*(\d+)\)').firstMatch(colorStr);
    if (match != null) {
      return Color.fromARGB(
        255,
        int.parse(match.group(1)!),
        int.parse(match.group(2)!),
        int.parse(match.group(3)!),
      );
    }
    return Colors.grey;
  }
}

